CREATE EXTENSION IF NOT EXISTS pgcrypto;
CREATE TABLE workspaces (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), name text NOT NULL, owner_discord_user_id text NOT NULL UNIQUE, default_output_language text NOT NULL DEFAULT 'pt-BR', read_later_channel_id uuid, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE discord_connections (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), workspace_id uuid NOT NULL REFERENCES workspaces(id) ON DELETE CASCADE, discord_guild_id text NOT NULL, guild_name text NOT NULL, bot_user_id text NOT NULL, status text NOT NULL DEFAULT 'connected', connected_at timestamptz NOT NULL DEFAULT now(), created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now(), UNIQUE(workspace_id, discord_guild_id));
CREATE TABLE channels (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), workspace_id uuid NOT NULL REFERENCES workspaces(id) ON DELETE CASCADE, discord_connection_id uuid NOT NULL REFERENCES discord_connections(id) ON DELETE CASCADE, discord_channel_id text NOT NULL, name text NOT NULL, parent_discord_channel_id text, parent_name text, discord_topic text, routing_description text, is_active_for_routing boolean NOT NULL DEFAULT true, is_read_later boolean NOT NULL DEFAULT false, availability text NOT NULL DEFAULT 'available' CHECK (availability IN ('available','unavailable')), last_synced_at timestamptz, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now(), UNIQUE(workspace_id, discord_channel_id));
CREATE UNIQUE INDEX channels_one_read_later_per_workspace ON channels(workspace_id) WHERE is_read_later;
ALTER TABLE workspaces ADD CONSTRAINT workspaces_read_later_fk FOREIGN KEY (read_later_channel_id) REFERENCES channels(id) ON DELETE SET NULL;
CREATE TABLE resources (id uuid PRIMARY KEY, workspace_id uuid NOT NULL REFERENCES workspaces(id) ON DELETE CASCADE, original_url text NOT NULL, normalized_url text NOT NULL, canonical_url text, canonical_url_key text NOT NULL, source_domain text NOT NULL, source_language text NOT NULL DEFAULT 'unknown', output_language text NOT NULL DEFAULT 'pt-BR', title text NOT NULL, description text, site_name text, author text, published_at_source timestamptz, image_url text, selected_quote text, summary text, why_useful text, personal_note text, enrichment_status text NOT NULL DEFAULT 'preparing' CHECK (enrichment_status IN ('preparing','ready','failed')), enrichment_error text, archived_at timestamptz, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now(), UNIQUE(workspace_id, canonical_url_key));
CREATE INDEX resources_workspace_created_idx ON resources(workspace_id, created_at DESC); CREATE INDEX resources_enrichment_idx ON resources(workspace_id, enrichment_status);
CREATE TABLE tags (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), workspace_id uuid NOT NULL REFERENCES workspaces(id) ON DELETE CASCADE, slug text NOT NULL, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now(), UNIQUE(workspace_id, slug));
CREATE TABLE tag_labels (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), tag_id uuid NOT NULL REFERENCES tags(id) ON DELETE CASCADE, language text NOT NULL, name text NOT NULL, UNIQUE(tag_id, language));
CREATE TABLE tag_aliases (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), workspace_id uuid NOT NULL REFERENCES workspaces(id) ON DELETE CASCADE, tag_id uuid NOT NULL REFERENCES tags(id) ON DELETE CASCADE, alias_normalized text NOT NULL, language text, UNIQUE(workspace_id, alias_normalized));
CREATE TABLE resource_tags (resource_id uuid NOT NULL REFERENCES resources(id) ON DELETE CASCADE, tag_id uuid NOT NULL REFERENCES tags(id) ON DELETE CASCADE, source text NOT NULL, PRIMARY KEY(resource_id, tag_id));
CREATE TABLE enrichment_runs (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), resource_id uuid NOT NULL REFERENCES resources(id) ON DELETE CASCADE, model text NOT NULL, prompt_version text NOT NULL, input_snapshot jsonb NOT NULL, output jsonb, status text NOT NULL, error text, duration_ms integer, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE deliveries (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), resource_id uuid NOT NULL REFERENCES resources(id) ON DELETE CASCADE, destination_type text NOT NULL, channel_id uuid REFERENCES channels(id), delivery_kind text NOT NULL, message_snapshot jsonb NOT NULL, external_message_id text, external_url text, status text NOT NULL DEFAULT 'pending', error text, sent_at timestamptz, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now()); CREATE INDEX deliveries_resource_idx ON deliveries(resource_id);
CREATE UNIQUE INDEX deliveries_success_guard ON deliveries(resource_id, channel_id, delivery_kind) WHERE status IN ('pending','sent');
CREATE TABLE auth_sessions (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), workspace_id uuid NOT NULL REFERENCES workspaces(id) ON DELETE CASCADE, refresh_token_hash text NOT NULL UNIQUE, expires_at timestamptz NOT NULL, revoked_at timestamptz, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE oauth_states (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), state_hash text NOT NULL UNIQUE, code_verifier text NOT NULL, expires_at timestamptz NOT NULL, consumed_at timestamptz, created_at timestamptz NOT NULL DEFAULT now());
